function saveUserDetails() {
  const nameInput = document.querySelector("#userNameInput");
  const emailInput = document.querySelector("#userEmailInput");
  const ageInput = document.querySelector("#userAgeInput");
  
  const nameVal = nameInput.value.trim();
  const emailVal = emailInput.value.trim();
  const ageVal = ageInput.value.trim();
  
  const nameError = document.querySelector("#nameError");
  const emailError = document.querySelector("#emailError");
  const ageError = document.querySelector("#ageError");
  let isValid = true;
  
  // Name Validation
  const nameRegex = /^[A-Za-z\s]{3,}$/;
  const distinctNameChars = new Set(nameVal.toLowerCase().replace(/\s/g, ''));
  if (!nameVal || !nameRegex.test(nameVal) || distinctNameChars.size < 2 || /(.)\1{3,}/i.test(nameVal)) {
    nameError.textContent = "Please enter a valid, real name.";
    nameError.style.display = "block";
    nameInput.style.borderColor = "#d93025";
    isValid = false;
  } else {
    nameError.style.display = "none";
    nameInput.style.borderColor = "var(--line)";
  }

  // Email Validation
  const emailRegex = /^[a-zA-Z0-9._%+-]{3,}@[a-zA-Z0-9.-]{3,}\.[a-zA-Z]{2,}$/;
  const domain = emailVal.split('@')[1]?.toLowerCase();
  const allowedDomains = ["gmail.com", "yahoo.com", "yahoo.co.in", "yahoo.in", "outlook.com", "hotmail.com", "icloud.com", "microsoft.com", "live.com", "me.com", "mac.com", "msn.com"];
  
  const isValidFormat = emailRegex.test(emailVal) && !/(.)\1{4,}/i.test(emailVal.split('@')[0]);
  const isAllowedDomain = allowedDomains.includes(domain);

  if (!emailVal || !isValidFormat || !isAllowedDomain) {
    emailError.textContent = (!emailVal || !isValidFormat) ? "Please enter a real email address." : "Please use a valid provider (gmail, yahoo, outlook, etc).";
    emailError.style.display = "block";
    emailInput.style.borderColor = "#d93025";
    isValid = false;
  } else {
    emailError.style.display = "none";
    emailInput.style.borderColor = "var(--line)";
  }

  // Age Validation
  if (!ageVal) {
    ageError.textContent = "Please select your age group.";
    ageError.style.display = "block";
    ageInput.style.borderColor = "#d93025";
    isValid = false;
  } else {
    ageError.style.display = "none";
    ageInput.style.borderColor = "var(--line)";
  }

  if (!isValid) return;
  
  // Autocorrect name to Title Case (Initcap)
  const formattedName = nameVal.toLowerCase().replace(/\b\w/g, c => c.toUpperCase());
  
  window.currentUser = {
    name: formattedName,
    email: emailVal.toLowerCase(),
    ageGroup: ageVal
  };
  
  isLoggedIn = true;
  document.querySelector("#loginButton").textContent = window.currentUser.name;
  saveQuizState();
  
  // Update result copy if it's currently showing
  const resultCopy = document.querySelector("#resultCopy");
  if (resultCopy && resultCopy.textContent.includes("Estimated annual")) {
    if (!resultCopy.textContent.startsWith("Hey")) {
      resultCopy.textContent = `Hey ${window.currentUser.name}! ` + resultCopy.textContent;
    }
  }

  // Re-sync payload to backend now that we have the name & email
  // Code.gs will perform an upsert using the same Response_ID
  saveQuizResponse(buildPayload()).catch(console.error);

  if (actionAfterLogin === "downloadOnly") {
    actionAfterLogin = null;
    downloadScore();
    showOnly("results");
    showThankYouScreen();
  } else if (actionAfterLogin === "download") {
    actionAfterLogin = null;
    downloadScore();
    backFromLogin();
  } else {
    actionAfterLogin = null;
    backFromLogin();
  }
}

